interface EQ {
  stem: string;
  options: string[];
  correctAnswer: number;
  rationale: string;
  learningObjective: string;
  blueprintCategory: string;
  subtopic: string;
  difficulty: number;
  cognitiveLevel: string;
  questionType: "multiple-choice" | "image-interpretation" | "calculation" | "clinical-case";
  scenario?: string;
  exhibitData?: any;
  exam: string;
  regionScope: "US" | "CAN" | "BOTH";
}

export function getBatch26(): EQ[] {
  return [
    { stem: "The bandwidth of a transducer determines:", options: ["Image brightness only", "The range of frequencies it can transmit and receive; broader bandwidth improves axial resolution", "Only Doppler accuracy", "Frame rate exclusively"], correctAnswer: 1, rationale: "Bandwidth: the range of frequencies a transducer can produce and detect. Broader bandwidth allows shorter pulses (better axial resolution) and supports harmonic imaging. Modern broadband transducers operate across a wide frequency range (e.g., 2-5 MHz).", learningObjective: "Describe transducer bandwidth", blueprintCategory: "Ultrasound Physics", subtopic: "Echo Imaging Physics", difficulty: 3, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The Q-factor (quality factor) of a transducer is:", options: ["A measure of image quality", "The ratio of operating frequency to bandwidth; low Q-factor means broader bandwidth and better imaging resolution", "The number of elements", "The cost rating"], correctAnswer: 1, rationale: "Q-factor = center frequency / bandwidth. Low Q (broad bandwidth) is preferred for imaging (short pulses, better resolution). High Q (narrow bandwidth) is preferred for CW Doppler (narrow frequency range for accurate velocity measurement).", learningObjective: "Define transducer Q-factor", blueprintCategory: "Ultrasound Physics", subtopic: "Echo Imaging Physics", difficulty: 4, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The spatial pulse length (SPL) determines:", options: ["Lateral resolution", "Axial resolution (axial resolution ≈ SPL/2)", "Temporal resolution", "Elevational resolution"], correctAnswer: 1, rationale: "SPL = number of cycles per pulse × wavelength. Axial resolution = SPL/2. Shorter SPL (fewer cycles, higher frequency) gives better axial resolution. SPL is the most important factor in axial resolution and is determined by the transducer characteristics.", learningObjective: "Relate SPL to axial resolution", blueprintCategory: "Ultrasound Physics", subtopic: "Echo Imaging Physics", difficulty: 3, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "Axial resolution in diagnostic ultrasound is typically:", options: ["5-10 mm", "0.5-2 mm (frequency-dependent)", "0.01 mm", "10-20 mm"], correctAnswer: 1, rationale: "Axial resolution is the best resolution in ultrasound, typically 0.5-2 mm. It equals SPL/2 and improves with higher frequency (shorter wavelength). At 5 MHz, axial resolution is approximately 0.3 mm. At 2 MHz, approximately 0.8 mm.", learningObjective: "State typical axial resolution values", blueprintCategory: "Ultrasound Physics", subtopic: "Echo Imaging Physics", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "Lateral resolution is determined primarily by:", options: ["Pulse length", "Beam width at the depth of interest", "Transducer frequency alone", "PRF"], correctAnswer: 1, rationale: "Lateral resolution equals the beam width at the depth of interest. It is best at the focal zone (narrowest beam). It worsens (degrades) in the far field as the beam diverges. Lateral resolution is always worse than axial resolution. Focusing improves it at the focal depth.", learningObjective: "Describe factors determining lateral resolution", blueprintCategory: "Ultrasound Physics", subtopic: "Echo Imaging Physics", difficulty: 3, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The piezoelectric effect converts:", options: ["Light to sound", "Electrical energy to mechanical (sound) energy and vice versa", "Heat to sound", "Magnetic fields to ultrasound"], correctAnswer: 1, rationale: "The piezoelectric effect: electrical voltage applied to a piezoelectric crystal causes mechanical deformation (produces ultrasound). Conversely, returning echoes deform the crystal, generating electrical signals (receive mode). PZT (lead zirconate titanate) is the most common piezoelectric material.", learningObjective: "Describe the piezoelectric effect", blueprintCategory: "Ultrasound Physics", subtopic: "Echo Imaging Physics", difficulty: 1, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "In ultrasound, attenuation includes contributions from:", options: ["Only reflection", "Absorption (conversion to heat), reflection, scattering, and refraction", "Only scattering", "Only absorption"], correctAnswer: 1, rationale: "Attenuation: total loss of ultrasound intensity as it propagates. Components: absorption (dominant, converts sound to heat), reflection (at interfaces), scattering (from small structures), and refraction (beam bending). Average attenuation in soft tissue: 0.5 dB/cm/MHz.", learningObjective: "List components of ultrasound attenuation", blueprintCategory: "Ultrasound Physics", subtopic: "Echo Imaging Physics", difficulty: 2, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The half-value layer (HVL) thickness is the depth at which ultrasound intensity:", options: ["Doubles", "Is reduced by half (3 dB)", "Is completely absorbed", "Is unchanged"], correctAnswer: 1, rationale: "HVL: the depth of tissue needed to reduce ultrasound intensity by half (3 dB attenuation). HVL decreases with increasing frequency (higher frequency = more attenuation = shallower HVL). In soft tissue at 1 MHz, HVL ≈ 3 cm; at 5 MHz, HVL ≈ 0.6 cm.", learningObjective: "Define the half-value layer", blueprintCategory: "Ultrasound Physics", subtopic: "Echo Imaging Physics", difficulty: 3, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "Acoustic impedance (Z) is calculated as:", options: ["Frequency × wavelength", "Density × speed of sound (Z = ρ × c)", "Velocity / frequency", "Attenuation × depth"], correctAnswer: 1, rationale: "Acoustic impedance Z = ρ × c (density × speed of sound). The percentage of ultrasound reflected at an interface depends on the impedance mismatch between the two tissues. Large mismatch (e.g., soft tissue-air, soft tissue-bone) = strong reflection.", learningObjective: "Calculate acoustic impedance", blueprintCategory: "Ultrasound Physics", subtopic: "Echo Imaging Physics", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The decibel (dB) scale in ultrasound is:", options: ["A linear scale", "A logarithmic scale where a 3 dB change represents doubling/halving of intensity", "An arbitrary scale", "A frequency scale"], correctAnswer: 1, rationale: "dB = 10 × log₁₀(I₂/I₁). A 3 dB change = 2× intensity change. A 10 dB change = 10× intensity. A 20 dB change = 100× intensity. The logarithmic scale compresses the enormous dynamic range of ultrasound signals into a manageable range.", learningObjective: "Describe the decibel scale", blueprintCategory: "Ultrasound Physics", subtopic: "Echo Imaging Physics", difficulty: 2, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The frame rate of an ultrasound image is calculated as:", options: ["PRF × depth", "PRF / number of scan lines per frame", "Frequency × depth", "Speed of sound / frame width"], correctAnswer: 1, rationale: "Frame rate = PRF / lines per frame. To increase frame rate: decrease depth (higher PRF), narrow sector width (fewer lines), reduce line density, or use parallel processing. Higher frame rates improve temporal resolution for moving structures.", learningObjective: "Calculate ultrasound frame rate", blueprintCategory: "Ultrasound Physics", subtopic: "Echo Imaging Physics", difficulty: 3, cognitiveLevel: "application", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "Time gain compensation (TGC) is used to:", options: ["Increase frequency", "Compensate for depth-dependent attenuation by increasing gain for deeper structures", "Decrease lateral resolution", "Change the Doppler angle"], correctAnswer: 1, rationale: "TGC applies variable gain at different depths to compensate for attenuation. Near-field gain is set lower and far-field gain higher, creating a uniform brightness display. Each TGC slider controls gain at a specific depth zone.", learningObjective: "Describe TGC function", blueprintCategory: "Ultrasound Physics", subtopic: "Echo Imaging Physics", difficulty: 1, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "Dynamic range (compression) on the echo machine controls:", options: ["Frame rate", "The range of echo amplitudes displayed; lower dynamic range increases contrast (more black and white), higher range shows more shades of gray", "Depth setting", "Transmit frequency"], correctAnswer: 1, rationale: "Dynamic range controls the compression of the echo signal amplitude range into the display gray scale. Low DR (~40 dB) creates high-contrast images (more binary black/white). High DR (~60-70 dB) shows more gray levels. Adjust based on clinical need: lower for contrast echo, higher for tissue characterization.", learningObjective: "Describe dynamic range control", blueprintCategory: "Ultrasound Physics", subtopic: "Echo Imaging Physics", difficulty: 2, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "A Doppler frequency shift of 3000 Hz is detected using a 3 MHz transducer at 0 degrees. The blood velocity is approximately:", options: ["0.39 m/s", "0.77 m/s", "1.54 m/s", "3.08 m/s"], correctAnswer: 1, rationale: "v = (Δf × c) / (2 × f₀ × cos θ) = (3000 × 1540) / (2 × 3,000,000 × 1) = 4,620,000 / 6,000,000 = 0.77 m/s. This is the Doppler equation solved for velocity.", learningObjective: "Calculate blood velocity from Doppler frequency shift", blueprintCategory: "Ultrasound Physics", subtopic: "Doppler Ultrasound", difficulty: 3, cognitiveLevel: "application", questionType: "calculation", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "In a patient with both AS and MS, the simplified Bernoulli equation for AS gradient:", options: ["Is always accurate", "May overestimate the AS gradient because the elevated proximal (LVOT) velocity from MS-induced LV underfilling is not accounted for", "Cannot be used", "Underestimates the gradient"], correctAnswer: 1, rationale: "When MS limits LV filling, the reduced preload decreases LVOT velocity, which could actually make the simplified Bernoulli more accurate. However, coexisting conditions can also elevate V1, making the modified Bernoulli (ΔP = 4(V2² - V1²)) more appropriate in complex valve disease.", learningObjective: "Understand Bernoulli limitations in mixed valve disease", blueprintCategory: "Hemodynamic Measurements", subtopic: "Hemodynamic Calculations", difficulty: 5, cognitiveLevel: "analysis", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "A patient with RV infarction typically shows:", options: ["LV dilation only", "RV dilation with RV wall motion abnormalities (particularly the inferior RV wall), elevated RAP, and normal or reduced LVEF if associated inferior LV MI", "Aortic root dilation", "Only pericardial effusion"], correctAnswer: 1, rationale: "RV infarction (usually from proximal RCA occlusion): RV dilation, RV free wall hypokinesis/akinesis (especially inferior segments), elevated RA pressure (IVC plethora), and often coexisting inferior LV wall motion abnormality. Hemodynamic hallmark: elevated RAP with low cardiac output.", learningObjective: "Describe echo findings of RV infarction", blueprintCategory: "Pathology Recognition", subtopic: "Ischemic Heart Disease", difficulty: 3, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "Hibernating myocardium on echo appears as:", options: ["Thin, bright, akinetic scar", "Chronically dysfunctional but viable myocardium that may show improvement in function with revascularization; typically normal wall thickness with reduced thickening", "Hyperkinetic segment", "Normal wall motion"], correctAnswer: 1, rationale: "Hibernating myocardium: chronically underperfused but viable tissue with reduced systolic function that can recover after revascularization. On echo: preserved or near-normal wall thickness (viable tissue) but reduced thickening. Dobutamine echo (biphasic response) and contrast echo assess viability.", learningObjective: "Describe hibernating myocardium echo characteristics", blueprintCategory: "Pathology Recognition", subtopic: "Ischemic Heart Disease", difficulty: 4, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "Stunned myocardium differs from hibernating myocardium in that stunning:", options: ["Is irreversible", "Is transient post-ischemic dysfunction that recovers spontaneously after restoration of blood flow, without need for revascularization", "Requires transplant", "Only occurs in the RV"], correctAnswer: 1, rationale: "Myocardial stunning: post-ischemic ventricular dysfunction that recovers spontaneously within hours to weeks after blood flow is restored (e.g., post-PCI, post-cardiac surgery). Unlike hibernation, it does not require ongoing revascularization for recovery. Wall thickness is preserved.", learningObjective: "Differentiate stunning from hibernation", blueprintCategory: "Pathology Recognition", subtopic: "Ischemic Heart Disease", difficulty: 3, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The biphasic response on dobutamine stress echo (improvement at low dose followed by worsening at high dose) indicates:", options: ["Normal response", "Viable but ischemic myocardium that may benefit from revascularization", "Non-viable scar tissue", "Fixed obstruction"], correctAnswer: 1, rationale: "Biphasic response: improvement in wall motion at low-dose dobutamine (5-10 mcg/kg/min, demonstrates viability/contractile reserve) followed by worsening at high dose (ischemia from flow-limiting stenosis). This pattern identifies viable, ischemic myocardium most likely to benefit from revascularization.", learningObjective: "Interpret the biphasic response on dobutamine echo", blueprintCategory: "Pathology Recognition", subtopic: "Stress Echocardiography", difficulty: 4, cognitiveLevel: "analysis", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The sensitivity of stress echocardiography for detecting coronary artery disease is approximately:", options: ["40-50%", "55-65%", "80-85%", "95-100%"], correctAnswer: 2, rationale: "Stress echo sensitivity for CAD detection is approximately 80-85% (specificity 80-90%). It is comparable to nuclear perfusion imaging in overall accuracy but has advantages: no radiation, higher specificity, lower cost, and real-time assessment of valve hemodynamics during stress.", learningObjective: "State stress echo sensitivity for CAD", blueprintCategory: "Pathology Recognition", subtopic: "Stress Echocardiography", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "A normal stress echo response shows:", options: ["New wall motion abnormalities", "Augmentation (increased wall motion and thickening) of all segments with increased heart rate", "Decreased wall motion", "No change in function"], correctAnswer: 1, rationale: "Normal stress echo response: all LV segments show augmented wall motion and systolic thickening at peak stress. EF increases. Any new or worsening wall motion abnormality (hypokinesis, akinesis, or dyskinesis) is abnormal and indicates stress-induced ischemia.", learningObjective: "Describe normal stress echo response", blueprintCategory: "Pathology Recognition", subtopic: "Stress Echocardiography", difficulty: 1, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "An echo shows a ventricular septal rupture 5 days after an acute anterior MI. The color Doppler shows:", options: ["No abnormal flow", "A high-velocity left-to-right shunt jet through the muscular septum with flow from LV to RV", "Only mitral regurgitation", "Aortic regurgitation"], correctAnswer: 1, rationale: "Post-MI ventricular septal rupture: color Doppler shows a left-to-right shunt through the ruptured septum (LV to RV) with high velocity flow. The CW Doppler gradient reflects the LV-RV pressure difference. Acute VSR causes hemodynamic collapse and is a surgical emergency.", learningObjective: "Identify post-MI VSD on echo", blueprintCategory: "Pathology Recognition", subtopic: "Ischemic Heart Disease", difficulty: 3, cognitiveLevel: "application", questionType: "clinical-case", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "A patient 3 days post-MI develops a new holosystolic murmur and cardiogenic shock. Echo should evaluate for:", options: ["Only LV function", "Acute papillary muscle rupture causing severe MR, ventricular septal rupture, or LV free wall rupture", "Only pericardial effusion", "Aortic dissection"], correctAnswer: 1, rationale: "New holosystolic murmur post-MI: differential includes papillary muscle rupture (acute severe MR) and ventricular septal rupture (left-to-right shunt). Free wall rupture causes tamponade. Echo with color Doppler differentiates these mechanical complications, all of which typically require emergent surgery.", learningObjective: "Evaluate post-MI mechanical complications", blueprintCategory: "Pathology Recognition", subtopic: "Ischemic Heart Disease", difficulty: 3, cognitiveLevel: "analysis", questionType: "clinical-case", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "An ischemic MR jet due to inferior MI is typically directed:", options: ["Posteriorly", "Anteriorly (toward the anterior mitral leaflet) due to tethering of the posterior leaflet from inferior wall dysfunction", "Centrally", "Laterally"], correctAnswer: 1, rationale: "Inferior MI causes posterior papillary muscle dysfunction and posterior leaflet tethering (Carpentier IIIb). This restricts posterior leaflet motion, and the MR jet is directed anteriorly (toward the non-restricted anterior leaflet). Anterior MI with anterolateral papillary dysfunction causes posteriorly-directed MR.", learningObjective: "Determine MR jet direction in ischemic MR", blueprintCategory: "Pathology Recognition", subtopic: "Ischemic Heart Disease", difficulty: 4, cognitiveLevel: "analysis", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "In CSCT practice, the sonographer must verify patient identity using:", options: ["Visual recognition only", "At least two patient identifiers (name, date of birth, medical record number) before starting the study", "Only the referral form", "No verification needed"], correctAnswer: 1, rationale: "Patient identification using at least two identifiers is a patient safety requirement in Canadian healthcare. This prevents wrong-patient studies and ensures correct correlation with prior studies and clinical information. It is part of the pre-examination checklist.", learningObjective: "Describe patient identification requirements", blueprintCategory: "Anatomy/Physiology", subtopic: "CSCT Exam Preparation", difficulty: 1, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "CSCT-CARDIAC", regionScope: "CAN" },
    { stem: "CSCT candidates should understand that echo measurements should be performed over how many cardiac cycles in sinus rhythm?", options: ["1 cycle", "3 cycles (or 5+ in atrial fibrillation) and averaged", "10 cycles", "20 cycles"], correctAnswer: 1, rationale: "In sinus rhythm, measurements should be averaged over 3 cardiac cycles for accuracy. In atrial fibrillation, 5-10 cycles should be averaged due to beat-to-beat variability. Measurements should avoid post-PVC beats and be taken at appropriate points in the cardiac cycle.", learningObjective: "State measurement cycle requirements", blueprintCategory: "Hemodynamic Measurements", subtopic: "CSCT Exam Preparation", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "CSCT-CARDIAC", regionScope: "CAN" },
    { stem: "A patient with Marfan syndrome and an aortic root of 4.8 cm with rapid growth (5 mm/year) should:", options: ["Continue routine monitoring", "Be referred for prophylactic aortic root replacement (threshold lowered to 4.5 cm with risk factors including rapid growth)", "Wait until 5.5 cm", "Only receive beta-blocker therapy"], correctAnswer: 1, rationale: "In Marfan syndrome, aortic root replacement is indicated at ≥5.0 cm. However, with risk factors (rapid growth >3 mm/year, family history of dissection, severe AR), the threshold is lowered to ≥4.5 cm. This patient at 4.8 cm with 5 mm/year growth meets criteria for surgery.", learningObjective: "Apply risk-adjusted surgical criteria in Marfan", blueprintCategory: "Pathology Recognition", subtopic: "Aortic Disease", difficulty: 4, cognitiveLevel: "analysis", questionType: "clinical-case", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The GLS value that is considered the threshold for subclinical LV dysfunction is:", options: ["<-24%", "<-20%", "Less negative than -16% (e.g., -14%, -12%)", "<-30%"], correctAnswer: 2, rationale: "GLS less negative than -16% (e.g., -14%, -12%) is generally considered abnormal and indicates subclinical LV dysfunction. Normal GLS is approximately -18% to -22% (vendor-dependent). Values in the -16% to -18% range are borderline. GLS detects dysfunction before EF declines.", learningObjective: "State the GLS threshold for subclinical dysfunction", blueprintCategory: "Hemodynamic Measurements", subtopic: "Advanced Echo Techniques", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "In the CSCT exam, knowledge of echo artifact recognition is essential because artifacts can:", options: ["Never affect clinical care", "Mimic pathology, obscure real pathology, or lead to misdiagnosis if not recognized", "Only occur with old equipment", "Be eliminated entirely with modern equipment"], correctAnswer: 1, rationale: "Echo artifacts are inherent to ultrasound physics and occur even with modern equipment. They can mimic masses (side lobes, reverberations), obscure structures (shadowing), or create false flow (ghosting). Recognition and differentiation from true pathology is a critical sonographer competency.", learningObjective: "Explain the clinical importance of artifact recognition", blueprintCategory: "Ultrasound Physics", subtopic: "CSCT Exam Preparation", difficulty: 2, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "CSCT-CARDIAC", regionScope: "CAN" },
    { stem: "The Bernoulli equation assumes all of the following EXCEPT:", options: ["Steady-state flow", "No energy loss to viscous friction", "Proximal velocity is negligible (simplified form)", "The stenotic orifice is always circular"], correctAnswer: 3, rationale: "The simplified Bernoulli equation (ΔP = 4V²) assumes: proximal velocity is negligible, viscous losses are negligible, and flow acceleration losses are negligible. It does NOT assume a circular orifice. These assumptions are generally valid for most clinical scenarios but break down in certain situations.", learningObjective: "Identify assumptions of the Bernoulli equation", blueprintCategory: "Hemodynamic Measurements", subtopic: "Hemodynamic Calculations", difficulty: 3, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The pressure recovery phenomenon is important in:", options: ["All echo assessments equally", "Aortic stenosis assessment in patients with small aortas (<30 mm), where Doppler may overestimate the true hemodynamic severity", "Only mitral stenosis", "Only TR assessment"], correctAnswer: 1, rationale: "Pressure recovery: kinetic energy is partially converted back to potential energy (pressure) downstream of a stenosis. In small aortas (<30 mm), significant pressure recovery occurs, meaning the Doppler-derived gradient overestimates the net hemodynamic gradient. The energy loss index (ELI) accounts for this.", learningObjective: "Describe pressure recovery in AS assessment", blueprintCategory: "Hemodynamic Measurements", subtopic: "Hemodynamic Calculations", difficulty: 5, cognitiveLevel: "analysis", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "An echo shows a quadricuspid aortic valve. This is:", options: ["The most common aortic valve variant", "A rare congenital variant (0.01-0.03%) with four cusps, associated with aortic regurgitation", "Always pathologic requiring immediate surgery", "The same as bicuspid valve"], correctAnswer: 1, rationale: "Quadricuspid aortic valve is a rare congenital variant seen in 0.01-0.03% of patients. It is best identified in the PSAX view showing four cusps with an 'X' closure pattern instead of the normal 'Y'. It is associated with progressive AR due to incomplete coaptation of the four unequal cusps.", learningObjective: "Describe quadricuspid aortic valve", blueprintCategory: "Pathology Recognition", subtopic: "Congenital Heart Defects", difficulty: 4, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "In echo, the term 'contractile reserve' during dobutamine stress refers to:", options: ["Normal resting function", "The ability of dysfunctional myocardium to improve in function with low-dose dobutamine stimulation, indicating viable tissue", "Maximum heart rate achieved", "Absence of ischemia"], correctAnswer: 1, rationale: "Contractile reserve: improvement in wall motion/thickening with low-dose dobutamine (5-10 mcg/kg/min). It indicates viable myocardium that may recover function with revascularization. Absence of contractile reserve suggests scar/non-viable tissue. Stroke volume increase ≥20% predicts surgical survival in low-flow AS.", learningObjective: "Define contractile reserve", blueprintCategory: "Pathology Recognition", subtopic: "Stress Echocardiography", difficulty: 3, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "An echo finding of 'ground glass' appearance of the myocardium with increased wall thickness and small LV cavity is suggestive of:", options: ["Normal heart", "Cardiac amyloidosis", "Dilated cardiomyopathy", "Pericardial constriction"], correctAnswer: 1, rationale: "The 'ground glass' or 'sparkling/granular' myocardial texture, combined with biventricular thickening, small LV cavity, biatrial enlargement, and restrictive diastolic filling, is the classic echo phenotype of cardiac amyloidosis. However, this texture is not always present.", learningObjective: "Identify the classic echo appearance of amyloidosis", blueprintCategory: "Pathology Recognition", subtopic: "Cardiomyopathies", difficulty: 3, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "Cardiac involvement in systemic sclerosis (scleroderma) on echo may include:", options: ["Only normal findings", "Pericardial effusion, diastolic dysfunction, pulmonary hypertension, and myocardial fibrosis", "Aortic root dilation only", "Only LV dilation"], correctAnswer: 1, rationale: "Scleroderma cardiac manifestations: pericardial effusion (~15-20%), diastolic dysfunction (myocardial fibrosis), pulmonary hypertension (from pulmonary fibrosis or pulmonary vascular disease), and less commonly LV systolic dysfunction. PH is a major prognostic factor.", learningObjective: "Describe cardiac echo findings in scleroderma", blueprintCategory: "Pathology Recognition", subtopic: "Cardiomyopathies", difficulty: 3, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "An echo in a patient with hypothyroidism may show:", options: ["Only tachycardia", "Pericardial effusion, diastolic dysfunction, and decreased LV systolic function that may improve with thyroid hormone replacement", "Aortic stenosis", "RV hypertrophy only"], correctAnswer: 1, rationale: "Hypothyroidism echo findings: pericardial effusion (most common, up to 30%), diastolic dysfunction, bradycardia, mildly reduced EF, and increased wall thickness (myxedematous infiltration). These changes typically reverse with thyroid hormone replacement therapy.", learningObjective: "Describe echo findings in hypothyroidism", blueprintCategory: "Pathology Recognition", subtopic: "Cardiomyopathies", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "In a patient with hyperthyroidism, echo may show:", options: ["Bradycardia only", "Increased cardiac output, atrial fibrillation, mild MR/TR, and sometimes dilated cardiomyopathy (thyrotoxic cardiomyopathy)", "Aortic stenosis", "Concentric hypertrophy only"], correctAnswer: 1, rationale: "Hyperthyroidism: increased CO (hyperdynamic state), AF (common), mild functional MR/TR, and in severe/chronic cases, high-output heart failure or thyrotoxic DCM with reduced EF. Treatment of the thyroid disorder typically reverses the cardiomyopathy.", learningObjective: "Describe echo findings in hyperthyroidism", blueprintCategory: "Pathology Recognition", subtopic: "Cardiomyopathies", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "A CSCT candidate must understand the importance of maintaining equipment calibration and quality assurance in the echo lab. This includes:", options: ["No specific requirements", "Regular transducer testing, phantom scanning, equipment maintenance logs, and verification of measurement accuracy", "Only replacing broken equipment", "Annual visual inspection only"], correctAnswer: 1, rationale: "Canadian echo lab accreditation requires documented equipment QA programs: regular transducer testing for sensitivity and dead elements, phantom scanning for measurement accuracy verification, preventive maintenance schedules, and documentation of all QA activities.", learningObjective: "Describe echo equipment QA requirements", blueprintCategory: "Ultrasound Physics", subtopic: "CSCT Exam Preparation", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "CSCT-CARDIAC", regionScope: "CAN" },
    { stem: "The CSCT exam covers the concept of echo in valvular heart disease severity grading. The integrative approach means:", options: ["Using only one parameter", "Combining structural assessment, Doppler hemodynamics, and consequences of the valve lesion (chamber dilation, function) for comprehensive severity determination", "Only measuring gradients", "Only using color Doppler"], correctAnswer: 1, rationale: "Integrative approach to valve disease: (1) structural assessment (valve morphology, mobility, calcification), (2) Doppler hemodynamics (gradients, EROA, RVol, vena contracta, PHT), and (3) consequences (chamber dilation, function, pulmonary pressures). All must be concordant for confident grading.", learningObjective: "Describe the integrative approach to valve grading", blueprintCategory: "Hemodynamic Measurements", subtopic: "CSCT Exam Preparation", difficulty: 2, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "CSCT-CARDIAC", regionScope: "CAN" },
  ];
}

export function getBatch27(): EQ[] {
  return [
    { stem: "An echo shows a large LA (LAVI 48 mL/m²) with normal E/A ratio (1.0) and normal E/e' ratio (8) in a patient with paroxysmal AF. Diastolic function is classified as:", options: ["Normal", "Indeterminate (LA enlargement may be from AF rather than elevated filling pressures)", "Grade II", "Grade III"], correctAnswer: 1, rationale: "In patients with AF (even paroxysmal), LA enlargement may be due to the arrhythmia itself rather than elevated filling pressures. With normal E/e' and E/A, the elevated LAVI alone does not confirm diastolic dysfunction. Clinical context is needed for classification.", learningObjective: "Interpret diastolic function in the context of AF", blueprintCategory: "Hemodynamic Measurements", subtopic: "Diastolic Function Assessment", difficulty: 4, cognitiveLevel: "analysis", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The normal aortic arch diameter is approximately:", options: ["10-15 mm", "20-35 mm", "40-50 mm", "60-70 mm"], correctAnswer: 1, rationale: "Normal aortic arch diameter is approximately 20-35 mm. Dilation of the arch may be seen in atherosclerosis, connective tissue disease, bicuspid aortopathy, or chronic hypertension. The arch is best assessed from the suprasternal notch view.", learningObjective: "State normal aortic arch diameter", blueprintCategory: "Anatomy/Physiology", subtopic: "Cardiac Anatomy", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "A patient with severe aortic stenosis but normal coronary arteries develops angina because:", options: ["The angina is unrelated to AS", "Increased LV wall stress and oxygen demand from LV hypertrophy exceeds supply, even without coronary disease", "The coronary arteries are always involved", "It is a psychosomatic symptom"], correctAnswer: 1, rationale: "Severe AS causes LV hypertrophy (increased wall thickness and mass), which increases myocardial oxygen demand (increased wall stress per LaPlace). The hypertrophied myocardium has reduced coronary flow reserve, creating a supply-demand mismatch even without epicardial coronary disease.", learningObjective: "Explain angina mechanism in severe AS without CAD", blueprintCategory: "Anatomy/Physiology", subtopic: "Cardiac Physiology", difficulty: 3, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "A subxiphoid (subcostal) view showing a thickened, echogenic pericardium with respiratory septal bounce suggests:", options: ["Cardiac tamponade", "Constrictive pericarditis", "Normal finding", "Dilated cardiomyopathy"], correctAnswer: 1, rationale: "Thickened pericardium (>4 mm by echo, confirmed by CT/MRI), septal bounce (respirophasic septal shift), and preserved/increased e' velocities are characteristic of constrictive pericarditis. The subcostal view best demonstrates pericardial thickening.", learningObjective: "Identify constrictive pericarditis from subcostal view", blueprintCategory: "Pathology Recognition", subtopic: "Pericardial Disease", difficulty: 3, cognitiveLevel: "application", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "An echo shows a massively dilated RA (area >28 cm²) with severe TR and normal PA pressures. The differential includes:", options: ["Only pulmonary hypertension", "Ebstein anomaly, primary TR from annular dilation, carcinoid disease, or RA volume overload from ASD", "Only coronary artery disease", "Only aortic dissection"], correctAnswer: 1, rationale: "Massive RA dilation with severe TR but normal PA pressures suggests primary TR (rather than secondary to PH). Causes include: Ebstein anomaly, primary annular dilation (idiopathic, AF), carcinoid disease, RV infarction, or ASD with chronic RA volume overload.", learningObjective: "Differentiate causes of massive RA dilation with normal PASP", blueprintCategory: "Pathology Recognition", subtopic: "Hemodynamics", difficulty: 4, cognitiveLevel: "analysis", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "Strain imaging can detect myocardial ischemia earlier than wall motion assessment because:", options: ["Strain uses contrast agents", "The ischemic cascade starts with perfusion abnormality then diastolic dysfunction then systolic dysfunction then WMA then ECG changes; strain detects early systolic changes", "Strain measures blood flow directly", "Strain has higher frame rate"], correctAnswer: 1, rationale: "The ischemic cascade: perfusion deficit → diastolic dysfunction → longitudinal dysfunction (strain abnormality) → circumferential/radial dysfunction → visible WMA → ECG changes → angina. Strain detects early longitudinal dysfunction before visual WMA becomes apparent.", learningObjective: "Explain strain sensitivity in the ischemic cascade", blueprintCategory: "Hemodynamic Measurements", subtopic: "Advanced Echo Techniques", difficulty: 4, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "A CSCT candidate should understand that the main limitation of 2D echo for LV volume assessment is:", options: ["Cost", "Geometric assumptions (foreshortening, shape assumptions) that can cause underestimation of true volumes", "Radiation exposure", "Inability to measure any volume"], correctAnswer: 1, rationale: "2D echo LV volume measurement limitations: apical foreshortening (underestimates true long axis and volumes), geometric assumptions (Simpson's assumes elliptical cross-sections), and dependence on endocardial border definition. 3D echo overcomes geometric assumptions and is more accurate.", learningObjective: "Identify limitations of 2D echo volume assessment", blueprintCategory: "Hemodynamic Measurements", subtopic: "CSCT Exam Preparation", difficulty: 3, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "CSCT-CARDIAC", regionScope: "CAN" },
    { stem: "In Canadian echo labs, the turnaround time for reporting a routine echo study should be:", options: ["Within 30 days", "Within a clinically appropriate timeframe (typically 24-48 hours for routine, immediately for urgent/critical)", "No time requirement", "Within 6 months"], correctAnswer: 1, rationale: "Canadian echo lab accreditation standards require timely reporting: critical findings must be communicated immediately, routine studies should be reported within 24-48 hours. Prolonged reporting delays can adversely affect patient care. Labs must have policies for report turnaround.", learningObjective: "State echo reporting turnaround time requirements", blueprintCategory: "Anatomy/Physiology", subtopic: "CSCT Exam Preparation", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "CSCT-CARDIAC", regionScope: "CAN" },
    { stem: "The normal descending aorta diameter is approximately:", options: ["5-10 mm", "15-25 mm", "30-40 mm", ">50 mm"], correctAnswer: 1, rationale: "Normal descending thoracic aorta diameter is approximately 15-25 mm (varies with body size and age). Dilation >25-30 mm may indicate aneurysm or dissection. The descending aorta is best assessed from the suprasternal, subcostal, or TEE views.", learningObjective: "State normal descending aorta diameter", blueprintCategory: "Anatomy/Physiology", subtopic: "Cardiac Anatomy", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "In a post-cardiac surgery patient, a new pericardial effusion localized posteriorly to the LA that compresses the LA may cause:", options: ["No hemodynamic effect", "Loculated effusion with hemodynamic compromise (regional tamponade) that may be missed by standard tamponade signs", "Aortic stenosis", "Only atrial arrhythmias"], correctAnswer: 1, rationale: "Post-surgical loculated pericardial effusions can cause regional tamponade by compressing specific chambers (commonly LA or RA). Standard tamponade signs may be absent because the fluid distribution is focal. TEE is often needed for diagnosis as TTE may have limited views post-surgery.", learningObjective: "Identify loculated pericardial effusion causing regional tamponade", blueprintCategory: "Pathology Recognition", subtopic: "Pericardial Disease", difficulty: 4, cognitiveLevel: "analysis", questionType: "clinical-case", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "An echo in a patient with chronic kidney disease shows bilateral pleural effusions, pericardial effusion, and LV hypertrophy. The LV hypertrophy pattern that would suggest amyloidosis rather than hypertensive heart disease is:", options: ["Concentric LV hypertrophy alone", "Biventricular wall thickening with granular sparkling, thickened interatrial septum, thickened valves, and restrictive filling (these features suggest infiltrative disease)", "Only mild septal hypertrophy", "LV dilation"], correctAnswer: 1, rationale: "Amyloidosis features distinguishing it from hypertensive LVH: biventricular (not just LV) thickening, thickened interatrial septum, thickened AV valves, granular sparkling, biatrial enlargement, restrictive filling, small voltage on ECG (paradox with wall thickness), and apical sparing strain pattern.", learningObjective: "Differentiate amyloid from hypertensive LVH", blueprintCategory: "Pathology Recognition", subtopic: "Cardiomyopathies", difficulty: 4, cognitiveLevel: "analysis", questionType: "clinical-case", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "An LVOT VTI of 12 cm in a hemodynamically unstable patient suggests:", options: ["Normal stroke volume", "Severely reduced stroke volume (low cardiac output state)", "Normal variant", "Measurement error"], correctAnswer: 1, rationale: "Normal LVOT VTI is 18-22 cm. VTI <15 cm indicates reduced stroke volume. VTI of 12 cm represents severely reduced SV. In the ICU, LVOT VTI trending is used to assess response to fluids, vasopressors, and inotropes.", learningObjective: "Interpret low LVOT VTI in critical care", blueprintCategory: "Hemodynamic Measurements", subtopic: "Hemodynamics", difficulty: 2, cognitiveLevel: "application", questionType: "clinical-case", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "A CSCT candidate should know that the most common indication for TEE in Canada is:", options: ["Routine screening", "Evaluation for endocarditis, intracardiac thrombus before cardioversion, intraoperative guidance, and structural heart intervention guidance", "Only for research purposes", "Only for pediatric patients"], correctAnswer: 1, rationale: "Common TEE indications in Canadian practice: suspected endocarditis (especially prosthetic valves), intracardiac thrombus evaluation before cardioversion, intraoperative cardiac surgery monitoring, structural heart intervention guidance (TAVR, MitraClip, ASD closure), and aortic dissection assessment.", learningObjective: "List common TEE indications in Canada", blueprintCategory: "Ultrasound Physics", subtopic: "CSCT Exam Preparation", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "CSCT-CARDIAC", regionScope: "CAN" },
  ];
}

export function getBatch28(): EQ[] {
  return [
    { stem: "A partial AV canal defect includes:", options: ["Only a VSD", "A primum ASD with a cleft in the anterior mitral valve leaflet causing MR", "Only an ASD", "Transposition of great arteries"], correctAnswer: 1, rationale: "Partial (incomplete) AV canal defect: primum ASD + cleft anterior mitral leaflet (directed toward the septum) causing MR of variable severity. Unlike complete AVSD, the mitral and tricuspid valves are separate (two separate AV valve annuli). Common in Down syndrome.", learningObjective: "Describe partial AV canal defect components", blueprintCategory: "Pathology Recognition", subtopic: "Congenital Heart Defects", difficulty: 3, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The Gerbode defect is a communication between:", options: ["Left atrium and right atrium", "Left ventricle and right atrium (LV-to-RA shunt due to defect in the membranous septum above the tricuspid valve)", "Aorta and pulmonary artery", "Left and right ventricles only"], correctAnswer: 1, rationale: "Gerbode defect: a VSD that creates a communication between the LV and RA (rather than LV-to-RV). This is possible because the tricuspid valve inserts more apically than the mitral, so a defect in the membranous septum above the TV can communicate directly with the RA. It creates a high-velocity left-to-right shunt.", learningObjective: "Describe the Gerbode defect", blueprintCategory: "Pathology Recognition", subtopic: "Congenital Heart Defects", difficulty: 5, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "Strain echocardiography in HCM may show:", options: ["Normal strain", "Reduced strain in the segments with maximum hypertrophy, often with a heterogeneous (mosaic) pattern on bull's-eye plot", "Only apical sparing", "Uniformly increased strain"], correctAnswer: 1, rationale: "HCM strain pattern: reduced (less negative) strain in maximally hypertrophied segments with relatively preserved strain in non-hypertrophied segments. This creates a heterogeneous/mosaic bull's-eye pattern that differs from the uniform reduction seen in DCM or the apical sparing of amyloidosis.", learningObjective: "Describe the HCM strain pattern", blueprintCategory: "Hemodynamic Measurements", subtopic: "Advanced Echo Techniques", difficulty: 4, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The normal acceleration time of the mitral E wave is:", options: ["<20 ms", "50-100 ms", ">200 ms", "300-400 ms"], correctAnswer: 1, rationale: "Normal mitral E wave acceleration time is approximately 50-100 ms. The deceleration time is clinically more important for diastolic function assessment (normal 160-200 ms). Both are measured from the mitral inflow PW Doppler at the leaflet tips.", learningObjective: "State normal mitral E wave acceleration time", blueprintCategory: "Hemodynamic Measurements", subtopic: "Diastolic Function Assessment", difficulty: 3, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "A peak MR velocity of 5.0 m/s with a systolic blood pressure of 120 mmHg. The estimated LA pressure is:", options: ["10 mmHg", "20 mmHg", "30 mmHg", "40 mmHg"], correctAnswer: 1, rationale: "LV-LA gradient = 4V² = 4(5.0)² = 100 mmHg. If LV systolic pressure ≈ SBP = 120 mmHg (no LVOT obstruction or AS), then LA pressure = LV systolic pressure - LV-LA gradient = 120 - 100 = 20 mmHg. This indicates mildly elevated LA pressure.", learningObjective: "Estimate LA pressure from MR velocity and SBP", blueprintCategory: "Hemodynamic Measurements", subtopic: "Hemodynamic Calculations", difficulty: 4, cognitiveLevel: "application", questionType: "calculation", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "An echo shows a patient with severe TR and hepatomegaly. The hepatic vein Doppler shows predominant diastolic forward flow with systolic reversal. The severity of TR based on hepatic vein flow is:", options: ["Mild", "Moderate", "Severe (systolic flow reversal is a specific sign)", "Normal"], correctAnswer: 2, rationale: "Hepatic vein systolic flow reversal is a specific sign of severe TR. Normal hepatic vein flow shows systolic forward flow > diastolic forward flow. As TR worsens: systolic flow decreases → becomes absent → reverses. Reversal confirms severe TR.", learningObjective: "Grade TR severity by hepatic vein flow", blueprintCategory: "Hemodynamic Measurements", subtopic: "Valvular Disease Assessment", difficulty: 3, cognitiveLevel: "application", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "A bioprosthetic valve typically degenerates after:", options: ["2-5 years", "5-10 years", "10-20 years", "Never degenerates"], correctAnswer: 2, rationale: "Bioprosthetic valves (porcine or bovine pericardial) have limited durability. Structural valve deterioration typically begins after 10-15 years (faster in younger patients, slower in elderly, mitral position degenerates faster than aortic). Signs include leaflet calcification, stenosis, and/or regurgitation.", learningObjective: "State bioprosthetic valve expected lifespan", blueprintCategory: "Pathology Recognition", subtopic: "Valvular Disease Assessment", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "In a patient with a bileaflet mechanical aortic valve, the normal number of regurgitant jets expected is:", options: ["0", "2-3 small central jets (washing jets)", "1 large jet", "5 jets"], correctAnswer: 1, rationale: "Bileaflet mechanical valves (St. Jude, On-X) have 2-3 small, symmetric washing jets: one through each leaflet hinge point and one between the two leaflets. These are intentional design features for thromboprophylaxis. Asymmetric or paravalvular jets suggest pathology.", learningObjective: "Identify normal mechanical valve washing jet pattern", blueprintCategory: "Pathology Recognition", subtopic: "Valvular Disease Assessment", difficulty: 3, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "CSCT candidates must know that the most common adverse event during TEE is:", options: ["Aortic dissection", "Oropharyngeal/esophageal trauma (sore throat, lip/tooth injury, mucosal laceration)", "Cardiac arrest", "Air embolism"], correctAnswer: 1, rationale: "The most common TEE adverse events are minor: sore throat (most frequent), lip or dental injury, and mucosal laceration. Serious complications are rare (<0.5%): esophageal perforation, aspiration, arrhythmia, and hypotension from sedation. Mortality is extremely rare (<0.01%).", learningObjective: "Identify the most common TEE adverse events", blueprintCategory: "Ultrasound Physics", subtopic: "CSCT Exam Preparation", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "CSCT-CARDIAC", regionScope: "CAN" },
    { stem: "An echo shows aortic valve thickening with reduced opening and a peak velocity of 2.8 m/s. This is classified as:", options: ["Aortic sclerosis", "Mild aortic stenosis (peak velocity 2.0-2.9 m/s)", "Moderate AS", "Severe AS"], correctAnswer: 1, rationale: "AS classification by peak velocity: sclerosis <2.0 m/s, mild 2.0-2.9 m/s, moderate 3.0-3.9 m/s, severe ≥4.0 m/s. A peak velocity of 2.8 m/s falls in the mild AS category. Annual echo follow-up is recommended for mild AS.", learningObjective: "Classify AS severity by peak velocity", blueprintCategory: "Pathology Recognition", subtopic: "Valvular Disease Assessment", difficulty: 2, cognitiveLevel: "application", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "A patient with HIV may develop which cardiac echo findings?", options: ["Only normal echo", "Pericardial effusion, dilated cardiomyopathy, pulmonary hypertension, and accelerated atherosclerosis", "Only aortic stenosis", "Only mitral stenosis"], correctAnswer: 1, rationale: "HIV-related cardiac disease: pericardial effusion (most common, ~10-40%), HIV-associated cardiomyopathy (dilated with reduced EF), pulmonary hypertension, accelerated atherosclerosis (from antiretroviral therapy and HIV inflammation), and rarely endocarditis (IVDU-related).", learningObjective: "Describe HIV-related cardiac echo findings", blueprintCategory: "Pathology Recognition", subtopic: "Cardiomyopathies", difficulty: 3, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The strain pattern in dilated cardiomyopathy typically shows:", options: ["Normal GLS", "Uniformly reduced (less negative) GLS across all segments", "Apical sparing", "Focal abnormality in a coronary territory"], correctAnswer: 1, rationale: "DCM strain pattern: uniformly reduced (less negative) GLS across all segments, reflecting global myocardial dysfunction. This differs from ischemic cardiomyopathy (regional patterns in coronary territories), HCM (heterogeneous), and amyloid (apical sparing).", learningObjective: "Describe the DCM strain pattern", blueprintCategory: "Hemodynamic Measurements", subtopic: "Advanced Echo Techniques", difficulty: 3, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "In the assessment of prosthetic valve function, the Doppler gradient should be compared to:", options: ["Only normal valve values", "The patient's own baseline postoperative gradient, as prosthetic gradients vary by valve type and size", "The contralateral valve", "Published surgical outcomes"], correctAnswer: 1, rationale: "Each prosthetic valve has expected normal gradients that vary by type (mechanical vs. bioprosthetic), manufacturer, and size. A baseline postoperative echo within 3-6 months establishes the patient's individual reference values. Future measurements are compared to this baseline.", learningObjective: "Explain baseline comparison for prosthetic valve assessment", blueprintCategory: "Hemodynamic Measurements", subtopic: "Valvular Disease Assessment", difficulty: 3, cognitiveLevel: "application", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
  ];
}

export function getBatch29(): EQ[] {
  return [
    { stem: "An echo in a patient with Chagas disease may show:", options: ["Normal echo always", "Dilated cardiomyopathy with apical aneurysm, apical thrombus, and segmental wall motion abnormalities", "Concentric LV hypertrophy only", "Isolated mitral stenosis"], correctAnswer: 1, rationale: "Chagas cardiomyopathy: apical aneurysm (highly characteristic, ~50%), segmental WMA (especially inferolateral and apical), progressive LV dilation with reduced EF, apical thrombus, and conduction abnormalities. It is endemic in Central and South America.", learningObjective: "Describe Chagas cardiomyopathy echo findings", blueprintCategory: "Pathology Recognition", subtopic: "Cardiomyopathies", difficulty: 4, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "An echo shows a patient with COPD and severe air trapping. The expected imaging difficulty is:", options: ["Excellent image quality", "Poor acoustic windows due to hyperinflated lungs, requiring subcostal approach or contrast enhancement", "Only M-mode available", "No imaging possible"], correctAnswer: 1, rationale: "COPD with hyperinflation causes poor parasternal and apical acoustic windows because expanded lungs interpose between the chest wall and heart. The subcostal approach (liver window) is often the best available. Contrast enhancement may be needed for endocardial border definition.", learningObjective: "Describe imaging challenges in COPD", blueprintCategory: "Ultrasound Physics", subtopic: "Echo Imaging Views", difficulty: 2, cognitiveLevel: "application", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "In obesity, echo imaging is challenging because:", options: ["The heart is smaller", "Increased distance between transducer and heart, greater attenuation, and limited acoustic windows reduce image quality", "Obesity improves image quality", "Only the heart size changes"], correctAnswer: 1, rationale: "Obesity challenges: increased chest wall thickness increases the distance and attenuation, limiting penetration. Acoustic windows may be restricted. Harmonic imaging and contrast enhancement improve endocardial visualization. Lower frequency transducers may be needed for penetration.", learningObjective: "Explain echo imaging challenges in obesity", blueprintCategory: "Ultrasound Physics", subtopic: "Echo Imaging Physics", difficulty: 2, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The near field length (Fresnel zone) of a transducer increases with:", options: ["Increased frequency and larger aperture", "Decreased frequency only", "Smaller aperture only", "Neither frequency nor aperture"], correctAnswer: 0, rationale: "Near field length = D²/(4λ) = D² × f/(4c), where D = aperture diameter and λ = wavelength. It increases with larger aperture (D) and higher frequency (shorter wavelength). The near field provides the best image quality; beyond it (far field), the beam diverges.", learningObjective: "Describe factors affecting near field length", blueprintCategory: "Ultrasound Physics", subtopic: "Echo Imaging Physics", difficulty: 3, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "A patient with severe tricuspid stenosis (TS) from carcinoid disease has a mean gradient of:", options: ["<2 mmHg", "≥5 mmHg (severe TS threshold)", "10-15 mmHg", "20-30 mmHg"], correctAnswer: 1, rationale: "Severe TS: mean gradient ≥5 mmHg, valve area <1.0 cm² (normal TV area 7-9 cm²), and prolonged pressure half-time. TS from carcinoid shows thickened, retracted leaflets with combined stenosis and regurgitation. TS can also occur from rheumatic disease.", learningObjective: "State criteria for severe tricuspid stenosis", blueprintCategory: "Pathology Recognition", subtopic: "Valvular Disease Assessment", difficulty: 3, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "Annulus paradoxus (annulus reversus) is a finding in constrictive pericarditis where:", options: ["Lateral e' > medial e' (normal)", "Medial e' > lateral e' (opposite of normal), because the rigid pericardium restricts lateral annular motion more than medial", "Both are equally reduced", "Both are normal"], correctAnswer: 1, rationale: "In constriction, the rigid/thickened pericardium restricts lateral mitral annular motion more than medial (which benefits from the relatively unconstrained septum). This reverses the normal pattern (lateral e' > medial e'), creating annulus paradoxus/reversus. This feature helps differentiate from RCM.", learningObjective: "Describe annulus paradoxus in constrictive pericarditis", blueprintCategory: "Pathology Recognition", subtopic: "Pericardial Disease", difficulty: 4, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "In effusive-constrictive pericarditis, echo shows:", options: ["Either effusion or constriction but not both", "Both pericardial effusion AND constrictive physiology, which persists after pericardiocentesis", "Only tamponade", "Normal findings"], correctAnswer: 1, rationale: "Effusive-constrictive pericarditis: combination of pericardial effusion (with or without tamponade) AND underlying constrictive physiology. After pericardiocentesis, the constriction becomes apparent (elevated filling pressures persist). It occurs in TB, post-radiation, and malignancy.", learningObjective: "Describe effusive-constrictive pericarditis", blueprintCategory: "Pathology Recognition", subtopic: "Pericardial Disease", difficulty: 5, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "A cardiac fibroma on echo appears as:", options: ["A mobile, pedunculated mass", "A large, homogeneous, echogenic intramural mass, typically in the LV free wall or septum, often with calcification", "An echo-free structure", "A thin membrane"], correctAnswer: 1, rationale: "Cardiac fibroma: the second most common pediatric cardiac tumor. It appears as a large, solitary, homogeneous, echogenic intramural mass (unlike myxoma which is intracavitary). Usually in the LV free wall or septum. Calcification may be present. It can cause arrhythmias and outflow obstruction.", learningObjective: "Describe cardiac fibroma echo appearance", blueprintCategory: "Pathology Recognition", subtopic: "Cardiac Masses", difficulty: 3, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "CSCT candidates must understand the difference between a focused (limited) and comprehensive echo. A focused echo:", options: ["Replaces comprehensive study", "Answers specific clinical questions with targeted imaging (e.g., LV function, effusion, volume status) but does not replace a comprehensive study", "Includes all standard views", "Is only for non-cardiac applications"], correctAnswer: 1, rationale: "A focused echo targets specific clinical questions in acute settings: Is there a pericardial effusion? What is the LV function? Is there RV dilation? What is the volume status? It does not include comprehensive chamber quantification, valve assessment, or hemodynamic measurements.", learningObjective: "Differentiate focused from comprehensive echo", blueprintCategory: "Ultrasound Physics", subtopic: "CSCT Exam Preparation", difficulty: 2, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "CSCT-CARDIAC", regionScope: "CAN" },
    { stem: "An echo measurement of stroke volume index (SVI) <35 mL/m² indicates:", options: ["Normal stroke volume", "Low-flow state that is important for classifying AS severity", "High cardiac output", "Normal variant"], correctAnswer: 1, rationale: "SVI = SV / BSA. Normal SVI is 40-50 mL/m². SVI <35 mL/m² defines low-flow state, which is important for classifying low-flow/low-gradient AS (both classical with reduced EF and paradoxical with preserved EF). SVI is calculated from LVOT area × LVOT VTI / BSA.", learningObjective: "Interpret stroke volume index for AS classification", blueprintCategory: "Hemodynamic Measurements", subtopic: "Hemodynamic Calculations", difficulty: 3, cognitiveLevel: "application", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "An aortic valve calcium score by CT >2000 AU (Agatston units) in males or >1200 AU in females strongly suggests:", options: ["Mild AS", "True severe AS (useful for confirming severity in low-gradient AS with preserved EF)", "Aortic sclerosis only", "Normal valve"], correctAnswer: 1, rationale: "CT aortic valve calcium scoring helps confirm AS severity when echo is discordant (e.g., low-gradient with preserved EF). Thresholds: males >2000 AU and females >1200 AU indicate very likely severe AS. Males >3000 AU = definite severe. This is part of the multimodality approach to AS assessment.", learningObjective: "Interpret AV calcium score for AS severity", blueprintCategory: "Hemodynamic Measurements", subtopic: "Hemodynamic Calculations", difficulty: 4, cognitiveLevel: "application", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "A patient with an echo showing 'swirl sign' in the LV apex after anterior MI has:", options: ["Normal apical flow", "Apical blood stasis with spontaneous swirling flow, indicating high risk for thrombus formation", "Aortic regurgitation", "Normal contractile function"], correctAnswer: 1, rationale: "The 'swirl sign' or spontaneous echo contrast in the LV apex after anterior MI indicates blood stasis due to apical akinesis/dyskinesis. This is a pre-thrombotic state with high risk for LV thrombus formation. Anticoagulation may be considered even before frank thrombus is visualized.", learningObjective: "Identify the LV swirl sign as a pre-thrombotic state", blueprintCategory: "Pathology Recognition", subtopic: "Ischemic Heart Disease", difficulty: 3, cognitiveLevel: "application", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "In the CSCT exam, understanding of patient positioning for echo includes:", options: ["Only supine position", "Left lateral decubitus for parasternal and apical views, supine for subcostal and right parasternal views, and seated/supine for suprasternal views", "Only sitting position", "Any position"], correctAnswer: 1, rationale: "Patient positioning affects image quality: left lateral decubitus brings the heart closer to the chest wall for parasternal and apical windows. Supine position is used for subcostal views (IVC assessment). Modifications may be needed for ICU patients, post-surgical patients, and those with limited mobility.", learningObjective: "Describe patient positioning for echo views", blueprintCategory: "Ultrasound Physics", subtopic: "CSCT Exam Preparation", difficulty: 1, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "CSCT-CARDIAC", regionScope: "CAN" },
  ];
}

export function getBatch30(): EQ[] {
  return [
    { stem: "An echo shows a Type I aortic dissection flap in the ascending aorta with severe AR. The mechanism of AR in dissection is:", options: ["Calcific degeneration", "Dilation of the aortic root disrupting cusp coaptation, prolapse of an aortic cusp by the dissection flap, or detachment of a commissure", "Rheumatic disease", "Endocarditis"], correctAnswer: 1, rationale: "AR in aortic dissection occurs by three mechanisms: (1) aortic root dilation disrupting cusp geometry, (2) asymmetric dissection prolapsing an aortic cusp, (3) commissural detachment. Acute severe AR in dissection is a surgical emergency and may cause rapid hemodynamic deterioration.", learningObjective: "Describe mechanisms of AR in aortic dissection", blueprintCategory: "Pathology Recognition", subtopic: "Aortic Disease", difficulty: 4, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "A modified Duke criterion for infective endocarditis includes which echo finding as a major criterion?", options: ["LV hypertrophy", "Oscillating intracardiac mass on a valve, abscess, new partial dehiscence of a prosthetic valve, or new valvular regurgitation", "Pericardial effusion alone", "Normal echo findings"], correctAnswer: 1, rationale: "Modified Duke major echo criteria: (1) oscillating intracardiac mass on a valve or supporting structures, in the path of regurgitant jets, or on implanted material, (2) abscess, (3) new partial dehiscence of prosthetic valve, (4) new valvular regurgitation. These are major diagnostic criteria.", learningObjective: "List Duke major echo criteria for IE", blueprintCategory: "Pathology Recognition", subtopic: "Valvular Disease Assessment", difficulty: 3, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "A TAPSE of 14 mm indicates:", options: ["Normal RV function", "Reduced RV longitudinal systolic function (abnormal <17 mm)", "Severely hyperdynamic RV", "Normal variant"], correctAnswer: 1, rationale: "TAPSE <17 mm indicates RV systolic dysfunction. TAPSE of 14 mm is abnormal. However, TAPSE measures only longitudinal function at a single point (lateral tricuspid annulus) and may be falsely low after cardiac surgery or in the presence of severe TR.", learningObjective: "Interpret TAPSE value indicating RV dysfunction", blueprintCategory: "Hemodynamic Measurements", subtopic: "RV Function Assessment", difficulty: 2, cognitiveLevel: "application", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "An echo in the ICU shows a dilated IVC (2.5 cm) with no inspiratory collapse in a mechanically ventilated patient. The estimated RAP is:", options: ["3 mmHg", "8 mmHg", "15 mmHg", "Cannot be determined in ventilated patients"], correctAnswer: 2, rationale: "In mechanically ventilated patients, IVC assessment is less reliable because positive pressure ventilation dilates the IVC. However, a markedly dilated IVC >2.1 cm with no collapse still suggests elevated RAP (~15 mmHg). IVC distensibility index (<18% = non-responsive to fluids) is used in ventilated patients.", learningObjective: "Interpret IVC in mechanically ventilated patients", blueprintCategory: "Hemodynamic Measurements", subtopic: "Hemodynamics", difficulty: 3, cognitiveLevel: "application", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "An echo shows a flail P2 segment of the mitral valve with severe eccentric MR directed anteriorly. The best surgical repair strategy is:", options: ["Mitral valve replacement", "Resection of P2 segment with sliding annuloplasty and ring annuloplasty (high repair success rate for P2 pathology)", "Medical management only", "Aortic valve replacement"], correctAnswer: 1, rationale: "Posterior leaflet pathology (especially P2 segment) has the highest repair success rate (>95%). Standard repair: triangular or quadrangular resection of the flail P2 segment, sliding annuloplasty, and complete ring annuloplasty. Anterior leaflet and bileaflet disease have lower repair rates.", learningObjective: "Identify optimal surgical approach for P2 flail", blueprintCategory: "Pathology Recognition", subtopic: "Valvular Disease Assessment", difficulty: 4, cognitiveLevel: "application", questionType: "clinical-case", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "Intracardiac echocardiography (ICE) is primarily used during:", options: ["Routine TTE", "Electrophysiology procedures, ASD/PFO closure, and other catheter-based interventions for real-time imaging guidance", "Stress echocardiography", "Outpatient screening"], correctAnswer: 1, rationale: "ICE uses a catheter-mounted transducer (typically placed in the RA or RV) for real-time imaging during: EP procedures (ablation guidance), ASD/PFO closure (defect sizing, device placement), transseptal puncture, and TAVR. Advantages over TEE: no general anesthesia needed.", learningObjective: "Describe ICE clinical applications", blueprintCategory: "Ultrasound Physics", subtopic: "Advanced Echo Techniques", difficulty: 3, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The most important error source in continuity equation AVA calculation is:", options: ["AV VTI measurement", "LVOT diameter measurement (because it is squared to calculate area)", "Heart rate variability", "Respiratory variation"], correctAnswer: 1, rationale: "LVOT diameter is the most critical measurement because it is squared (πr²) to calculate LVOT area. A 1 mm error results in ~7-10% error in area and AVA. Consistent measurement at the same location (inner edge to inner edge, in mid-systole, in zoomed PLAX) is essential.", learningObjective: "Identify the most important error source in AVA calculation", blueprintCategory: "Hemodynamic Measurements", subtopic: "Hemodynamic Calculations", difficulty: 3, cognitiveLevel: "analysis", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "CSCT candidates must know that the leading edge method for LV dimension measurement means:", options: ["Measuring from the brightest point", "Measuring from the anterior edge (leading edge) of one interface to the anterior edge of the next interface", "Measuring from center to center", "Measuring trailing edge to leading edge"], correctAnswer: 1, rationale: "Leading edge to leading edge: the standard ASE convention for M-mode and 2D measurements. The leading edge is the first reflective interface encountered by the ultrasound beam. For 2D-guided measurements, inner-edge to inner-edge convention is also used for some measurements.", learningObjective: "Describe the leading edge measurement convention", blueprintCategory: "Hemodynamic Measurements", subtopic: "CSCT Exam Preparation", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "CSCT-CARDIAC", regionScope: "CAN" },
    { stem: "Echo shows a right atrial mass in a patient with renal cell carcinoma. The mass extends from the IVC into the RA. This is most likely:", options: ["Myxoma", "Tumor thrombus (direct extension of RCC through the renal vein and IVC into the RA)", "Eustachian valve", "Chiari network"], correctAnswer: 1, rationale: "Renal cell carcinoma is notorious for extending through the renal vein into the IVC and sometimes into the RA as tumor thrombus. Echo (especially TEE or subcostal TTE) can visualize the extent of intracardiac tumor extension, which is critical for surgical planning.", learningObjective: "Identify tumor thrombus from RCC extending into the heart", blueprintCategory: "Pathology Recognition", subtopic: "Cardiac Masses", difficulty: 3, cognitiveLevel: "application", questionType: "clinical-case", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "The normal pulmonary artery acceleration time (PAAT) is:", options: ["<60 ms", "60-100 ms", ">120 ms", ">200 ms"], correctAnswer: 2, rationale: "Normal PAAT (RVOT acceleration time) is >120 ms. PAAT <100 ms suggests pulmonary hypertension (shorter AT reflects higher pulmonary vascular impedance). PAAT <60 ms with mid-systolic notching is highly specific for elevated PVR.", learningObjective: "State normal PAAT values", blueprintCategory: "Hemodynamic Measurements", subtopic: "Hemodynamic Calculations", difficulty: 2, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "An echo in a patient with suspected cardiac contusion after blunt chest trauma should evaluate for:", options: ["Only aortic stenosis", "RV wall motion abnormalities, pericardial effusion, valvular damage (especially tricuspid), and new wall motion abnormalities", "Only LV mass", "Only mitral prolapse"], correctAnswer: 1, rationale: "Cardiac contusion (from blunt chest trauma): the RV is most vulnerable due to its anterior position. Echo findings include RV wall motion abnormalities, pericardial effusion (possible hemopericardium), tricuspid valve damage (most commonly injured valve in trauma), and rarely ventricular septal rupture.", learningObjective: "Describe echo assessment after blunt chest trauma", blueprintCategory: "Pathology Recognition", subtopic: "Pathology Recognition", difficulty: 3, cognitiveLevel: "recall", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
    { stem: "A CSCT candidate should understand that ultrasound gel coupling is essential because:", options: ["It improves patient comfort only", "It eliminates the air-skin interface that would reflect >99% of the ultrasound energy due to massive acoustic impedance mismatch", "It changes the ultrasound frequency", "It is only used for cosmetic reasons"], correctAnswer: 1, rationale: "The acoustic impedance mismatch between air (Z = 0.0004 × 10⁶ kg/m²s) and skin/tissue (Z ≈ 1.63 × 10⁶ kg/m²s) is enormous, causing >99.9% reflection. Coupling gel eliminates this air layer, allowing efficient transmission of ultrasound into the body.", learningObjective: "Explain the purpose of ultrasound coupling gel", blueprintCategory: "Ultrasound Physics", subtopic: "CSCT Exam Preparation", difficulty: 1, cognitiveLevel: "comprehension", questionType: "multiple-choice", exam: "CSCT-CARDIAC", regionScope: "CAN" },
    { stem: "Doppler tissue imaging at the lateral mitral annulus shows S' = 12 cm/s, E' = 14 cm/s, and A' = 8 cm/s. These values indicate:", options: ["Severely impaired function", "Normal systolic and diastolic function", "Isolated diastolic dysfunction", "Isolated systolic dysfunction"], correctAnswer: 1, rationale: "Normal lateral annular velocities: s' ≥10 cm/s (systolic), e' ≥12 cm/s (early diastolic). These values are all within normal range, indicating preserved systolic (s') and diastolic (e') function. The A' reflects atrial contraction contribution.", learningObjective: "Interpret normal TDI velocities", blueprintCategory: "Hemodynamic Measurements", subtopic: "Diastolic Function Assessment", difficulty: 2, cognitiveLevel: "application", questionType: "multiple-choice", exam: "RDCS-AE", regionScope: "BOTH" },
  ];
}
